import org.joda.time.Chronology;
import org.joda.time.DateTimeField;
import org.joda.time.DurationField;
import org.joda.time.chrono.ISOChronology;
import org.joda.time.DateTimeFieldType;

public class InspectFields {
    public static void main(String[] args) {
        Chronology chrono = ISOChronology.getInstanceUTC();

        DateTimeField weekyear = chrono.weekyear();
        DateTimeField month = chrono.monthOfYear();
        DateTimeField week = chrono.weekOfWeekyear();

        System.out.println("Weekyear: " + weekyear.getName());
        printDuration("Weekyear Range", weekyear.getRangeDurationField());
        printDuration("Weekyear Duration", weekyear.getDurationField());

        System.out.println("\nMonth: " + month.getName());
        printDuration("Month Range", month.getRangeDurationField());
        printDuration("Month Duration", month.getDurationField());

        System.out.println("\nWeek: " + week.getName());
        printDuration("Week Range", week.getRangeDurationField());
        printDuration("Week Duration", week.getDurationField());

        // Emulate compareReverse
        System.out.println("\nComparisons (compareReverse):");
        System.out.println("Weekyear Range vs Month Range: " + compareReverse(weekyear.getRangeDurationField(), month.getRangeDurationField()));
        System.out.println("Month Range vs Week Range: " + compareReverse(month.getRangeDurationField(), week.getRangeDurationField()));
    }

    static void printDuration(String label, DurationField field) {
        if (field == null) {
            System.out.println(label + ": null");
        } else {
            System.out.println(label + ": " + field.getName() + " supported=" + field.isSupported() + " unitMillis=" + (field.isSupported() ? field.getUnitMillis() : "N/A"));
        }
    }

    static int compareReverse(DurationField a, DurationField b) {
        if (a == null || !a.isSupported()) {
            if (b == null || !b.isSupported()) {
                return 0;
            }
            return -1;
        }
        if (b == null || !b.isSupported()) {
            return 1;
        }
        return -a.compareTo(b);
    }
}

import org.joda.time.Chronology;
import org.joda.time.DateTimeField;
import org.joda.time.chrono.ISOChronology;
import org.joda.time.format.DateTimeFormat;
import org.joda.time.format.DateTimeFormatter;

public class TraceSet {
    public static void main(String[] args) {
        Chronology chrono = ISOChronology.getInstanceUTC();

        long millis = 0; // 1970-01-01

        System.out.println("Start: " + print(millis));

        DateTimeField weekyear = chrono.weekyear();
        DateTimeField month = chrono.monthOfYear();
        DateTimeField week = chrono.weekOfWeekyear();

        // Step 1: Set weekyear 2010
        millis = weekyear.set(millis, 2010);
        System.out.println("After weekyear=2010: " + print(millis));

        // Step 2: Set month 1
        millis = month.set(millis, 1);
        System.out.println("After month=1:       " + print(millis));

        // Step 3: Set week 1
        millis = week.set(millis, 1);
        System.out.println("After week=1:        " + print(millis));
    }

    static String print(long millis) {
        return DateTimeFormat.forPattern("yyyy-MM-dd (xxxx-ww-e)").withZoneUTC().print(millis);
    }
}
